// Nó: "Split Output do Agente" (Function node)
const results = [];
console.log("INPUT COUNT:", $input.all().length);

const palavrasExcluir = [
  'qualificar_leads',
  'Workflow was started',
  'Used tools',
  '[qualificar_leads]',
  '[used tools:',
  'Input',
  '[input:'
];

function contemPalavrasTecnicas(texto) {
  const textoLower = texto.toLowerCase();
  return palavrasExcluir.some(palavra =>
    textoLower.includes(palavra.toLowerCase())
  );
}

function sanitizeText(texto) {
  return texto
    // ── 1. Remove artefatos do agente ────────────────────────────────
    .replace(/\[.*?\]/gs, '')                     // [xxx] → remove
    .replace(/```[\s\S]*?```/g, '')               // blocos ```código``` → remove
    .replace(/`[^`]*`/g, '')                      // `inline code` → remove

    // ── 2. Corrige formatações malfeitas do agente ───────────────────
    .replace(/\*\*(.+?)\*\*/gs, '*$1*')          // **texto** → *texto*
    .replace(/\\([^\\\n"]{1,80})\\/g, '*$1*')    // \texto\ → *texto*
    .replace(/_([^\n_]{1,80})_/g, '*$1*')        // _texto_ → *texto*

    // ── 2. Remove lixo invisível ─────────────────────────────────────
    .replace(/\r/g, '')
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '')

    // ── 3. Normaliza aspas curly ─────────────────────────────────────
    .replace(/[""]/g, '"')
    .replace(/['']/g, "'")

    // ── 4. Escapa para JSON string (ORDEM IMPORTA) ───────────────────
    .replace(/\\/g, '\\\\')   // \ → \\  (SEMPRE PRIMEIRO)
    .replace(/"/g, '\\"')     // " → \"
    .replace(/\t/g, '\\t')   // tab literal → \t
    .replace(/\n/g, '\\n')   // newline literal → \n

    .trim();
}

for (const item of $input.all()) {
  const rawOutput = item.json.output ?? item.json.text ?? item.json.response ?? item.json.texto ?? item.json;
  let aiData;

  try {
    if (typeof rawOutput === 'string') {
      aiData = JSON.parse(rawOutput);
    } else {
      aiData = rawOutput;
    }
  } catch (err) {
    aiData = { texto: String(rawOutput ?? ''), adicionais: {} };
  }

  // Se texto for array, junta tudo em uma string única
  if (Array.isArray(aiData.texto)) {
    const textoJunto = aiData.texto
      .map(t => String(t).trim())
      .filter(t => t && !contemPalavrasTecnicas(t))
      .join('\n');

    if (textoJunto) {
      results.push({ json: { texto: sanitizeText(textoJunto), adicionais: aiData.adicionais || {} } });
    }
    continue;
  }

  if (aiData && aiData.texto) {
    const textoOriginal = String(aiData.texto);

    // Remove aspas das pontas se existirem
    const textoLimpo = textoOriginal
      .replace(/^["'"]|["'"]$/g, '')
      .trim();

    if (contemPalavrasTecnicas(textoLimpo) || textoLimpo.length === 0) {
      results.push({
        json: {
          texto: sanitizeText("Eu pedi para a responsável entrar em contato contigo, então já já ela te chama aqui, assim que possível para responder todas as suas dúvidas."),
          adicionais: aiData.adicionais || {}
        }
      });
    } else {
      results.push({
        json: {
          texto: sanitizeText(textoLimpo),
          adicionais: aiData.adicionais || {}
        }
      });
    }
  } else {
    results.push(item);
  }
}

console.log("OUTPUT COUNT:", results.length);
return results;

